//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFGreenProfileCmd::MRFGreenProfileCmd() :
CATStateCommand ("MRFGreenProfileCmd", CATDlgEngOneShot, CATCommandModeExclusive)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pMRFGreenProfileDlg(NULL)
, _pApplicationFrame(NULL)
, _pEditor(NULL)
, _pHSO(NULL)
, _pISO(NULL)
, _spCBUOnCurrObject(NULL)
, _spMechanicalPart(NULL_var)
, _spPrtCont(NULL_var)
, _spMRFGSDFactory(NULL_var)
, _spGreenProfileGeomSet(NULL_var)
{

	_pApplicationFrame = CATApplicationFrame::GetFrame();
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
		_pISO = _pEditor->GetISO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		_spCBUOnCurrObject = oActivePath.NextFatherElement();

		CATUnicodeString objName;
		if (!!_spCBUOnCurrObject)
			objName = MRFGenericUtils::GetAliasName(_spCBUOnCurrObject);

		if (NULL_var != _spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			_spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart && NULL_var == _spMechanicalPart)
			{
				_spMechanicalPart = piPrtPart;
				piPrtPart->Release();  piPrtPart = NULL;
			}

			if (NULL_var != _spMechanicalPart)
			{
				CATUnicodeString strGPGeomSet = "Green Profiles";
				CATIPartRequest_var spPartRequest;
				spPartRequest = _spMechanicalPart;
				if (NULL_var != spPartRequest)
				{
					CATListValCATBaseUnknown_var spGeomSets;
					spPartRequest->GetSurfBodies("MfDefault3DView", spGeomSets);
					for (int i = 1; i <= spGeomSets.Size() && NULL_var == _spGreenProfileGeomSet; i++)
					{
						CATIAlias_var spAlias = spGeomSets[i];
						if (NULL_var != spAlias && 2 == spAlias->GetAlias().Compare(strGPGeomSet))
							_spGreenProfileGeomSet = spGeomSets[i];
					}
				}

				_spMechanicalPart->GetPrtContainer(_spPrtCont);
				if (NULL_var != _spPrtCont)
				{
					_spMRFGSDFactory = _spPrtCont;
				}

				GetListOfUDFUnderAPart(_spMechanicalPart);
			}
		}
	}


	_selectedConfigNameIndexFromCombo = 0;
	_selectedConfigName = "";
	_pMRFGreenProfileDlg = new MRFGreenProfileCmdDlg();

	ReadNLSAtStart((CATString)NLSName);

	_pMRFGreenProfileDlg->Build();
	_pMRFGreenProfileDlg->SetVisibility(CATDlgShow);

	SetComboBoxFromConfigFile(); //Call this function after building the UI
}

//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFGreenProfileCmd::~MRFGreenProfileCmd()
{
	if (_pMRFGreenProfileDlg)
		_pMRFGreenProfileDlg->RequestDelayedDestruction(); _pMRFGreenProfileDlg = NULL;

	if (_pApplicationFrame)
		_pApplicationFrame = NULL;

	if (_pEditor)
		_pEditor = NULL;

	if (_pHSO)
	{
		_pHSO->Empty();
		_pHSO = NULL;
	}

	if (_pISO)
		_pISO = NULL;

	//-------------------------Newly Released Starts----------------//
	if (!!_spMechanicalPart)
		_spMechanicalPart = NULL_var;

	if (!!_spPrtCont)
		_spPrtCont = NULL_var;

	if (!!_spMRFGSDFactory)
		_spMRFGSDFactory = NULL_var;
	
	if (!!_spGreenProfileGeomSet)
		_spGreenProfileGeomSet = NULL_var;
}


