//-------------------------------------------------------------------------
// FindNonEditableParamFromTree : Find non edtable paramerers available under specification tree
//-------------------------------------------------------------------------
void MRFGreenProfileCmd::FindNonEditableParamFromTree()
{
	if (!_spMechanicalPart)
		return;

	if (_pListOfConfigInfo.Size() > 0)
	{
		for (int i = 1; i <= _pListOfConfigInfo.Size(); i++)
		{
			ConfigInfo *pConfigInfo = (ConfigInfo*)_pListOfConfigInfo[i];
			CATListValCATUnicodeString ListOfParamFromNLS = pConfigInfo->strList_ParamFromTree;
			if (ListOfParamFromNLS.Size() > 0)
			{
				for (int j = 1; j <= ListOfParamFromNLS.Size(); j++)
				{
					CATBaseUnknown_var spFoundFeat;

					spFoundFeat = FindParametersUnderTree(_spMechanicalPart, ListOfParamFromNLS[j]);

					if (spFoundFeat)
						pConfigInfo->List_ParamFromTree.Append(spFoundFeat);
					else
					{
						spFoundFeat = FindParametersUnderUDFList(ListOfParamFromNLS[j]);

						if (spFoundFeat)
							pConfigInfo->List_ParamFromTree.Append(spFoundFeat);
					}

				}
			}
		}
	}
}

//-------------------------------------------------------------------------
// FindParametersUnderTree : Find parameters under the specification tree
//-------------------------------------------------------------------------
CATBaseUnknown_var MRFGreenProfileCmd::FindParametersUnderTree(CATIMmiUsePrtPart_var spMechPrt, CATUnicodeString paramName)
{
		CATBaseUnknown_var spParmToStore;
	if (!!spMechPrt)
	{
		CATListValCATBaseUnknown_var spListOfParm;
		CATIKweModelServices_var spModelServices =  CATCkeGlobalFunctions::GetModelServices();
		if (!!spModelServices)
		{
			spModelServices->VisibleParms(spMechPrt, spListOfParm);
			/*CATICkeParameterSet_var spParmPublisher = spModelServices->GetCurrentSet(CATIKweModelServices::Parameter);
			if (!!spParmPublisher)
			{
				CATCkeListOfParm spParmList =	spParmPublisher->Parameters();*/
				if (spListOfParm.Size() > 0)
				{
					for (int i = 1; i <= spListOfParm.Size() && spParmToStore == NULL_var; i++)
					{
						CATICkeParm_var spParm = (spListOfParm)[i];
						if (!!spParm)
						{
							//CATUnicodeString nameOfParmLoc = spParm->Name();
							CATUnicodeString nameOfParmLoc = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spParm);
							if (nameOfParmLoc.Compare(paramName) >= 1)
							{
								spParmToStore = spParm;
							}
						}

					}
				}
			//}
		}
	}

	return spParmToStore;
}

//-------------------------------------------------------------------------
// FindFeatureFromUDFList : Find feature from UDF list
//-------------------------------------------------------------------------
CATBaseUnknown_var MRFGreenProfileCmd::FindFeatureFromUDFList(CATUnicodeString featNameToFind)
{
	CATBaseUnknown_var spFeatFound;
	if (_spListOfUDFUnderCATPrt.Size() > 0)
	{
		for (int i = 1; i <= _spListOfUDFUnderCATPrt.Size() && spFeatFound == NULL_var; i++)
		{
			CATIUdfFeatureInstance_var spUDFInst = _spListOfUDFUnderCATPrt[i];
			if (!!spUDFInst)
			{
				int outCount = 0;
				spUDFInst->GetOutputsNumber(outCount);
				for (int j = 1; j <= outCount && spFeatFound == NULL_var; j++)
				{
					spUDFInst->GetOutput(j, spFeatFound);
					CATUnicodeString nameOfFeat;
					CATIAlias_var spAliasOnOutName = spFeatFound;
					if (spAliasOnOutName != NULL_var)
					{
						nameOfFeat = spAliasOnOutName->GetAlias();
					}

					if (nameOfFeat.SearchSubString(featNameToFind) == -1)
						spFeatFound = NULL_var;
				}
				//spUDFInst->GetOutput(featNameToFind, spFeatFound);
			}
		}

	/*	if (spFeatFound == NULL_var)
		{
			CATUnicodeString msg = "The Below Feature Not Found \n";
			msg.Append(featNameToFind);
			MRFGenericUtils::ShowErrorMessage(msg);
		}*/
	}

	return spFeatFound;
}

