//-------------------------------------------------------------------------
// CollectUserParamFromNLS : Collect list of user parameters and values from the list 
//-------------------------------------------------------------------------
map<string,double> MRFGreenProfileCmd::CollectUserParamFromNLS(CATListValCATUnicodeString listOfUserParmWithVal)
{
	map<string, double> userpam;

	if (listOfUserParmWithVal.Size() > 0)
	{

		for (int i = 1; i <= listOfUserParmWithVal.Size(); i++)
		{
			string UserParm = listOfUserParmWithVal[i];

			stringstream strStream(UserParm);
			string name,val;

			int j = 0;
			while (strStream.good())
			{
				if (j == 0)
				{
					getline(strStream, name, '=');
					j++;
				}
				else if(j==1)
					getline(strStream, val, '=');
			}

			double dVal = 0;
			if(val !="")
				dVal = stod(val);
			userpam.insert(pair<string,double>(name, dVal));

		}
	}

	return userpam;
}

//-------------------------------------------------------------------------
// PopulateMultiListUserParam : Populate multi list with user parameters
//-------------------------------------------------------------------------
void MRFGreenProfileCmd::PopulateMultiListUserParam(CATDlgMultiList *pMultiList)
{
	if (pMultiList && _selectedConfigNameIndexFromCombo == 0)
	{
		pMultiList->ClearLine();

	}

	if (pMultiList && _selectedConfigNameIndexFromCombo > 0 && _pListOfConfigInfo.Size() > 0 && _selectedConfigNameIndexFromCombo <= _pListOfConfigInfo.Size())
	{
		pMultiList->ClearLine();

		ConfigInfo *pConfigInfo = (ConfigInfo*)_pListOfConfigInfo[_selectedConfigNameIndexFromCombo];
		if (pConfigInfo)
		{
			map<string, double>::iterator itr = pConfigInfo->userParameters.begin();


			int j = 1;
			for (itr; itr != pConfigInfo->userParameters.end(); ++itr,++j)
			{
				string nameOfSurface = itr->first;
				CATUnicodeString sNo, val;
				sNo.BuildFromNum(j);
				val.BuildFromNum(itr->second);

				pMultiList->SetColumnItem(0, sNo, -1, CATDlgDataAdd);
				pMultiList->SetColumnItem(1, nameOfSurface.c_str(), -1, CATDlgDataAdd);
				pMultiList->SetColumnItem(2, val, -1, CATDlgDataAdd);



			}
		}

	}
}

//-------------------------------------------------------------------------
// OnGenerateFeaturePushButtonClicked : Called when Create Feature button is pushed
//-------------------------------------------------------------------------
void MRFGreenProfileCmd::OnGenerateFeaturePushButtonClicked(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (0 == _selectedConfigNameIndexFromCombo)
	{
		MRFGenericUtils::ShowErrorMessage("Invalid GreenProfile selected.");
		return;
	}
		
		

	if (_spMRFIGreenProfileSet != NULL_var)
	{
		MRFGenericUtils::ShowErrorMessage("Green Profile already created.");
		return;
	}
	
	if (NULL_var != _spMechanicalPart && !!_spMRFGSDFactory)
	{
		if (NULL_var == _spGreenProfileGeomSet)
		{
			CATUnicodeString strGPGeomSet = "Green Profiles";
			CATIGSMTool *pGSMTool_GreenProfile = NULL;
			MRFGenericUtils::CreateGSMToolUnderGivenFeature(_spMechanicalPart, pGSMTool_GreenProfile, TRUE, strGPGeomSet);
			if (!!pGSMTool_GreenProfile)
			{
				_spGreenProfileGeomSet = pGSMTool_GreenProfile;
				pGSMTool_GreenProfile->Release(); pGSMTool_GreenProfile = NULL;
			}
				
		}
		else
		{
			CATINavigateObject_var spNavigateObject = _spGreenProfileGeomSet;
			if (spNavigateObject != NULL_var)
			{
				CATLISTV(CATBaseUnknown_var)* pListChildren = spNavigateObject->GetChildren();
				if (NULL != pListChildren)
				{
					int size = pListChildren->Size();
					if (size > 0)
					{
						for (int i = 1; i <= size && NULL_var == _spMRFIGreenProfileSet; i++)
						{
							_spMRFIGreenProfileSet = (*pListChildren)[i];
							if (NULL_var != _spMRFIGreenProfileSet)
							{
								CATUnicodeString strConfiGName = "";
								_spMRFIGreenProfileSet->GetConfigName(strConfiGName);
								if (2 != strConfiGName.Compare(_selectedConfigName))
									_spMRFIGreenProfileSet = NULL_var;
							}
						}
					}
				}
			}
		}
			
		if (NULL_var == _spMRFIGreenProfileSet)
			_spMRFGSDFactory->CreateGreenProfileSet(_spMRFIGreenProfileSet);
		if (NULL_var != _spGreenProfileGeomSet && !!_spMRFIGreenProfileSet)
		{
			SetGreenProfileValue(_spMRFIGreenProfileSet);
			CATIMmiMechanicalFeature_var spGreenProfileSetFeat = _spMRFIGreenProfileSet;
			if (NULL_var != spGreenProfileSetFeat)
			{
				spGreenProfileSetFeat->ChangeMechanicalFather(_spGreenProfileGeomSet);
				MRFGenericUtils::UpdateFeature(spGreenProfileSetFeat, _spGreenProfileGeomSet, TRUE);
				CATIMmiUsePrtPart_var spPrtPart = _spMechanicalPart;
				if (NULL_var != spPrtPart)
					spPrtPart->SetInWorkObject(spGreenProfileSetFeat);
			}
			_pMRFGreenProfileDlg->SetAPPLYSensitivity(CATDlgEnable);
			CATListValCATBaseUnknown_var spGreenProfileList, spParmList;
			_spMRFIGreenProfileSet->GetGreenProfileList(spGreenProfileList);
			for (int i = 1; i <= spGreenProfileList.Size(); i++)
			{
				MRFIGreenProfile_var spGreenProfile = spGreenProfileList[i];
				if (NULL_var != spGreenProfile)
				{
					CATUnicodeString strName = "";
					spGreenProfile->GetGreenProfileName(strName);

					CATIAlias_var spAlias = spGreenProfileList[i];
					if (NULL_var != spAlias)
					{
						CATUnicodeString strAlias = spAlias->GetAlias();

						if (strAlias.Compare(strName) < 2)
						{
							spAlias->SetAlias(strName);
						}
					}
				}
			}
			
		}

	}
	return;

}

//-------------------------------------------------------------------------
// SetGreenProfileValue : Used to set values from spec tree object and multi list to Green Profile  Set
//-------------------------------------------------------------------------
void MRFGreenProfileCmd::SetGreenProfileValue(const MRFIGreenProfileSet_var & spGreenProfileSet)
{
	int comboIndex = _selectedConfigNameIndexFromCombo;
	CATUnicodeString strConfigName_TyreFeat, exeFileName, exeFilePath;
	double fineElemCurWidth = 0, profileSplitterInnerLength = 0, profileSplitterOuterLength = 0;
	CATListValCATBaseUnknown_var listOfSurfaces, listOfParamFromTree, list_UserParameters;
	CATBaseUnknown_var spSmoothenedCurve_StartPoint, spSmoothenedCurve;
	CATListValCATUnicodeString vpUserParam;

	if (comboIndex > 0 && _pListOfConfigInfo.Size() > 0 && comboIndex <= _pListOfConfigInfo.Size())
	{
		ConfigInfo *pConfigFile = (ConfigInfo*)_pListOfConfigInfo[comboIndex];
		if (pConfigFile)
		{
			vpUserParam = pConfigFile->strList_UserParameters;

			strConfigName_TyreFeat = pConfigFile->strConfigName_TyreFeature;
			exeFileName = pConfigFile->exeFileName;
			exeFilePath = pConfigFile->exeFilePath;
			fineElemCurWidth = pConfigFile->finiteElementCuredWidth;
			listOfSurfaces = pConfigFile->List_InputSurfaces;
			listOfParamFromTree = pConfigFile->List_ParamFromTree;
			list_UserParameters = pConfigFile->List_UserParameters;
			profileSplitterInnerLength = pConfigFile->profileSplitterInnerLength;
			profileSplitterOuterLength = pConfigFile->profileSplitterOuterLength;
			spSmoothenedCurve_StartPoint = pConfigFile->spSmoothenedCurve_StartPoint;
			spSmoothenedCurve = pConfigFile->spSmoothenedCurve;
		}

	}

	spGreenProfileSet->SetConfigName(strConfigName_TyreFeat);
	spGreenProfileSet->SetConfigComboIndex(_selectedConfigNameIndexFromCombo);
	spGreenProfileSet->SetSurfaceList(listOfSurfaces);
	spGreenProfileSet->SetParametersFromTree(listOfParamFromTree);
	spGreenProfileSet->SetUserParameters(vpUserParam);
	spGreenProfileSet->SetSmoothenedCurve(spSmoothenedCurve);
	spGreenProfileSet->SetSmoothenedCurveStartPoint(spSmoothenedCurve_StartPoint);
	spGreenProfileSet->SetExeFileName(exeFileName);
	spGreenProfileSet->SetExeFilePath(exeFilePath);
	spGreenProfileSet->SetFiniteElementCuredWidth(fineElemCurWidth);
	spGreenProfileSet->SetProfileSplitterOuterLength(profileSplitterOuterLength);
	spGreenProfileSet->SetProfileSplitterInnerLength(profileSplitterInnerLength);

	CATIAlias_var spAlias = spGreenProfileSet;
	if (NULL_var != spAlias)
	{
		CATUnicodeString strName = strConfigName_TyreFeat;
		//strName.Append("_GreenProfile");
		spAlias->SetAlias(strName);
	}
}

